mapper.update:
UPDATE tb_notification
SET IS_READ  = 1,
    READ_TIME = NOW()
WHERE NOTIF_NO = #{notifNo}
  AND RECIPIENT_USERNAME = #{username}

mapper.select:
SELECT COUNT(*) > 0
FROM tb_notification
WHERE RECIPIENT_USERNAME = #{recipientUsername}
  AND REF_NO = #{refNo}
  AND TITLE = #{title}
  AND CREATE_TIME  >=  CURDATE()
